import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getMoveChainIntelligence(walletAddress) {
  const [sui, aptos] = await Promise.all([
    client.BalanceService.getTokenBalancesForWalletAddress("sui-mainnet", walletAddress),
    client.BalanceService.getTokenBalancesForWalletAddress("aptos-mainnet", walletAddress),
  ]);
  return { sui: sui.data?.items, aptos: aptos.data?.items };
}
